// // This module decodes a two-bit input to produce a one-bit output. For input '10', the output is '1'. For all other inputs ('00' and '01'), the output is determined by the least significant bit.
module top_module( 
    input   [1:0]  data,
    output  reg    q
    );always @(*)
    begin
        if (data == 2'b10)
            q = 1'b0;
        else
            q = data[1];
    end

endmodule
